#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 10000
#define MAX_M 10000

// Define the structure for a graph edge
typedef struct {
    int u, v;
} Edge;

// Define the structure for a graph
typedef struct {
    int n, m;
    Edge edges[MAX_M];
    int adj[MAX_N][MAX_N];
} Graph;

// Function to read the graph from input
void readGraph(Graph *g) {
    int i, u, v;
    scanf("%d %d", &g->n, &g->m);
    for (i = 0; i < g->m; i++) {
        scanf("%d %d", &u, &v);
        g->edges[i].u = u;
        g->edges[i].v = v;
        g->adj[u][v] = 1;
        g->adj[v][u] = 1;
    }
}

// Function to calculate the Grundy number for each city
void calculateGrundy(Graph *g, int *grundy) {
    int i, j, k;
    for (i = 0; i < g->n; i++) {
        grundy[i] = 0;
        for (j = 0; j < g->n; j++) {
            if (g->adj[i][j] == 1) {
                grundy[i] ^= (1 << j);
            }
        }
    }
}

// Function to determine the winning strategy
void determineWinningStrategy(Graph *g, int *grundy, int *aircrafts) {
    int i, j, k;
    int xor = 0;
    for (i = 0; i < g->n; i++) {
        xor ^= grundy[i];
    }
    if (xor == 0) {
        printf("Wolverine\n");
    } else {
        printf("Deadpool\n");
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        Graph g;
        int aircrafts[MAX_N];
        int grundy[MAX_N];
        readGraph(&g);
        for (i = 0; i < g.n; i++) {
            scanf("%d", &aircrafts[i]);
        }
        calculateGrundy(&g, grundy);
        determineWinningStrategy(&g, grundy, aircrafts);
    }
    return 0;
}

