        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();
            int[][] adj = new int[n][n];
            for (int i = 0; i < m; i++) {
                int u = sc.nextInt();
                int v = sc.nextInt();
                adj[u][v] = 1;
                adj[v][u] = 1;
            }
            int[] aircrafts = new int[n];
            for (int i = 0; i < n; i++) {
                aircrafts[i] = sc.nextInt();
            }
            int[] grundy = new int[n];
            for (int i = 0; i < n; i++) {
                grundy[i] = 0;
                for (int j = 0; j < n; j++) {
                    if (adj[i][j] == 1) {
                        grundy[i] ^= (1 << j);
                    }
                }
            }
            int xor = 0;
            for (int i = 0; i < n; i++) {
